window.__QUIZ_DATA__=[{"id":"objective>Civic Education>2019>1","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS","question":"Fundamental rights are literally the rights that one can enjoy because one is","images":[],"options":{"A":"an individual.","B":"a human being.","C":"a citizen,","D":"an educated elite."},"answer":"B","explanation":"Fundamental rights are the basic human rights that every individual is entitled to because they are a human being. These rights are inherent and not dependent on factors such as citizenship or education.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>2","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF DEMOCRACY","question":"Which of the following nationalists is associated with democratic socialism?","images":[],"options":{"A":"Ahmadu Bello","B":"Tafawa Balewa","C":"Anthony Enahoro","D":"Obafemi Awolowo"},"answer":"D","explanation":"Obafemi Awolowo is associated with democratic socialism. He was a Nigerian nationalist and statesman who played a key role in Nigeria's independence movement, the First and Second Republics and the Civil War. He was the first premier of the Western Region and later federal commissioner for finance, and he was thrice a major contender for his country's highest office. Awolowo was one of the principal participants in the country's formative political and constitutional development. He was the leader of the Action Group party that implemented free primary education in the Western Region and established the first television service in Africa in 1959.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>3","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION","question":"When a person is being fair, impartial and reasonable in dealing with others, such person is said to be","images":[],"options":{"A":"responsible.","B":"tolerant.","C":"honest.","D":"humble."},"answer":"B","explanation":"When a person is being fair, impartial and reasonable in dealing with others, such person is said to be tolerant. Tolerance is the ability or willingness to tolerate the existence of opinions or behavior that one dislikes or disagrees with. It involves respecting the rights and beliefs of others, even if they are different from our own. It is a key aspect of good citizenship and a peaceful society.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>4","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : LIMITATIONS TO THE EXERCISE OF HUMAN RIGHTS","question":"A limitation to the exercise of human right is","images":[],"options":{"A":"war","B":"deportation","C":"migration","D":"HIV/AIDS"},"answer":"A","explanation":"A limitation to the exercise of human rights can be war. During war, certain rights such as the right to movement, right to assembly, and even right to life can be infringed upon. This is because during war, the primary focus is usually on survival and victory, rather than the protection of individual rights.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>5","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : MEANING OF CONSTITUTED AUTHORITY","question":"Which of the following is not among the sources of authority?","images":[],"options":{"A":"Societal","B":"Traditional","C":"Rational Legal","D":"Charismatic"},"answer":"C","explanation":"Rational Legal is not a source of authority. The sources of authority are typically Traditional, Charismatic, and Legal-rational. Traditional authority is based on established belief in the sanctity of immemorial traditions and the legitimacy of the status of those exercising authority under them. Charismatic authority is power legitimized by the level of devotion of the followers for the leader. Legal-rational authority is power legitimized by legally enacted rules and regulations such as governments.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>6","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY","question":"Orderliness can be exhibited in the following ways except","images":[],"options":{"A":"observing the traffic lights.","B":"queuing culture.","C":"decorum behaviour.","D":"interrupting an individual."},"answer":"D","explanation":"Orderliness is about maintaining a sense of organization and discipline in one's activities or behavior. It involves following rules, regulations, and societal norms. Options 1, 2, and 3 are all examples of orderliness as they involve following rules or norms (traffic lights, queuing, and decorum behavior). However, option 4, 'interrupting an individual', is not an example of orderliness. It is generally considered rude and disruptive to interrupt someone, which goes against the concept of orderliness.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>7","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : IMPORTANCE OF RESPONSIBLE PARENTHOOD IN NATIONAL DEVELOPMENT","question":"Which of the following is a way of achieving responsible parenthood?","images":[],"options":{"A":"Commitment","B":"Patriotism","C":"Favouritism","D":"Goodness"},"answer":"A","explanation":"Responsible parenthood involves various aspects, including providing for the physical, emotional, and social needs of children. This requires a high level of commitment from parents. Therefore, option 1, 'Commitment', is the correct answer. The other options, 'Patriotism', 'Favouritism', and 'Goodness', while they may be desirable qualities, are not directly related to the concept of responsible parenthood.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>8","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP","question":"A citizen is someone who","images":[],"options":{"A":"holds a chieftaincy title in the country.","B":"is a legal member of the country.","C":"has lived in the country for a long time.","D":"is a staunch supporter of the country's development."},"answer":"B","explanation":"A citizen is a person who is legally recognized as a member of a state or country. The person has the rights and protection of that state or country. The person can also be a native or naturalized member of a state, nation, or country, who owes allegiance to its government and is entitled to its protection.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>9","subject":"Civic Education","year":"2019","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM","question":"Incidences of broken home and irresponsible parenthood are the major causes of the following except","images":[],"options":{"A":"unhealthy growth.","B":"armed robbery.","C":"migration.","D":"cultism."},"answer":"C","explanation":"Broken homes and irresponsible parenthood can lead to a variety of social problems, including unhealthy growth, armed robbery, and cultism. However, migration is not directly caused by broken homes or irresponsible parenthood. Migration can be caused by a variety of factors, including economic opportunities, political instability, and environmental factors.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>10","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : GOALS OF CITIZENSHIP EDUCATION","question":"Citizenship education will not help to achieve which of the following?","images":[],"options":{"A":"National unity","B":"Education of the youth","C":"Moral decadence","D":"Promoting democracy"},"answer":"C","explanation":"Citizenship education is a type of education that teaches individuals about their rights, responsibilities, and duties as citizens. It also promotes values such as national unity, democracy, and the importance of education. However, it does not directly address moral decadence. Moral decadence refers to the decline in moral standards, which is a societal issue that needs to be addressed through various means, not just through citizenship education.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>11","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY","question":"Use the story to answer this question  One fateful morning, Imasuen was going to school. A few distance away from the school gate, he saw an accident victim writhing in severe pain by the road side. The accident victim was hit by a motorcycle rider and left half-dead. Although Imasuen was already late for school, he decided to convey the victim to a nearby hospital before reporting the matter to a nearby police station.    From the story above, it could be said that Imasuen have demonstrated","images":[],"options":{"A":"honesty","B":"fair play","C":"tolerance","D":"selflessness"},"answer":"D","explanation":"From the story, Imasuen demonstrated selflessness. Selflessness is the quality of caring more about other people than about oneself. Despite being late for school, Imasuen decided to help the accident victim, showing that he cared more about the victim's wellbeing than his own convenience. This act of putting others before oneself is a clear demonstration of selflessness.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>12","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY","question":"Use the story to answer this question  One fateful morning, Imasuen was going to school. A few distance away from the school gate, he saw an accident victim writhing in severe pain by the road side. The accident victim was hit by a motorcycle rider and left half-dead. Although Imasuen was already late for school, he decided to convey the victim to a nearby hospital before reporting the matter to a nearby police station.  The behaviour of the motorcycle rider in the above story depicts","images":[],"options":{"A":"arrogance.","B":"unruly attitude.","C":"cruelty.","D":"aggressive behaviour."},"answer":"C","explanation":"The behavior of the motorcycle rider in the story depicts 'cruelty'. This is because the rider hit a person and left them half-dead without offering any help or reporting the incident. This act of indifference and lack of empathy towards the victim's suffering is a clear indication of cruelty.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>13","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY","question":"Use the story to answer this question  One fateful morning, Imasuen was going to school. A few distance away from the school gate, he saw an accident victim writhing in severe pain by the road side. The accident victim was hit by a motorcycle rider and left half-dead. Although Imasuen was already late for school, he decided to convey the victim to a nearby hospital before reporting the matter to a nearby police station.  The behaviour of Imasuen in the story above can help promote all the following except","images":[],"options":{"A":"orderliness.","B":"peaceful coexistence.","C":"punctuality.","D":"stability."},"answer":"C","explanation":"The behavior of Imasuen in the story promotes orderliness, peaceful coexistence, and stability as he showed empathy, responsibility, and care for the victim. However, it does not promote punctuality. In the story, Imasuen was already late for school and he decided to help the victim instead of going to school on time. Therefore, his actions, while commendable, did not promote punctuality.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>14","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF NATIONALISM","question":"Nationalism is a product of all the following features except","images":[],"options":{"A":"cultural similarity","B":"social complexity","C":"shared interest","D":"historical association."},"answer":"B","explanation":"Nationalism is a political ideology that involves a strong identification of a group of individuals with a political entity defined in national terms, i.e. a nation. It is often associated with the belief that a particular nation should be autonomous, and its people should have a shared interest, cultural similarity, and historical association. However, social complexity, which refers to the differentiation in social roles, status, and access to resources among members of a society, is not a product of nationalism. In fact, it can sometimes challenge the unity and homogeneity that nationalism seeks to promote.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>15","subject":"Civic Education","year":"2019","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING","question":"Trafficked individuals are likely to have been","images":[],"options":{"A":"corrupt and greedy.","B":"traumatized and stigmatized.","C":"dangerous and heartless.","D":"hardworking and courageous."},"answer":"B","explanation":"Human trafficking is a serious crime and a grave violation of human rights. Every year, thousands of men, women and children fall into the hands of traffickers, in their own countries and abroad. Trafficked individuals are often subjected to physical and emotional abuse, which can lead to trauma and stigmatization. The other options do not accurately describe the likely state of trafficked individuals.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>16","subject":"Civic Education","year":"2019","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : DRUGS THAT CAN BE ABUSED","question":"The drug usually referred to as marijuana is","images":[],"options":{"A":"cannabis.","B":"cocaine,","C":"caffeine.","D":"heroin."},"answer":"A","explanation":"Marijuana is a common name for cannabis, a psychoactive drug from the Cannabis plant. It is used for medical or recreational purposes. The other options listed, cocaine, caffeine, and heroin, are different substances and not referred to as marijuana.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>17","subject":"Civic Education","year":"2019","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : MEANING OF YOUTH EMPOWERMENT","question":"The process of acquisition of necessary skills by young people for national development is known as","images":[],"options":{"A":"sponsorship.","B":"encouragement.","C":"motivation.","D":"empowerment."},"answer":"D","explanation":"The process of acquisition of necessary skills by young people for national development is known as empowerment. Empowerment refers to the process of becoming stronger and more confident, especially in controlling one's life and claiming one's rights. It often involves the empowered developing confidence in their own capacities. The other options, sponsorship, encouragement, and motivation, are not processes of acquiring skills.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>18","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE","question":"The Federal Road Safety Corps (FRSC) carries out all these functions except","images":[],"options":{"A":"construction of motorable roads.","B":"effective patrol operation.","C":"inspection of vehicles.","D":"prompt rescue mission."},"answer":"A","explanation":"The Federal Road Safety Corps (FRSC) is a Para-military organization and the lead agency in Nigeria on road safety administration and management. The statutory functions include: Making the highways safe for motorists and other road users as well as checking road worthiness of vehicles, educating motorists and members of the public on the importance of road discipline on the highways, and providing prompt rescue services on the highways. However, the construction of motorable roads is not part of their duties. This is typically the responsibility of government agencies like the Federal Ministry of Works or state Public Works Departments.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>19","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS","question":"The inalienable entitlement of an individual in a society are known as","images":[],"options":{"A":"basic necessities.","B":"natural justice.","C":"fundamental freedom.","D":"human rights."},"answer":"D","explanation":"The inalienable entitlements of an individual in a society are known as human rights. Human rights are rights inherent to all human beings, regardless of race, sex, nationality, ethnicity, language, religion, or any other status. They include the right to life and liberty, freedom from slavery and torture, freedom of opinion and expression, the right to work and education, and many more. Everyone is entitled to these rights, without discrimination.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>20","subject":"Civic Education","year":"2019","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : MEANING AND ORIGIN OF CULTISM","question":"Membership of an organization that is characterized by secrecy of operations is associated with","images":[],"options":{"A":"activism.","B":"cultism.","C":"radicalism.","D":"spiritism."},"answer":"B","explanation":"Cultism is often characterized by secrecy of operations. Cults usually operate in a clandestine manner, with their activities hidden from non-members. This is to maintain the exclusivity of the group and to avoid detection by law enforcement agencies. Activism, radicalism, and spiritism do not necessarily involve secrecy of operations.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>21","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF DEMOCRACY","question":"The inability of citizens of a country to freely elect their leaders is a threat to","images":[],"options":{"A":"federalism.","B":"totalitarianism.","C":"oligarchy.","D":"democracy."},"answer":"D","explanation":"The inability of citizens to freely elect their leaders is a threat to democracy. Democracy is a system of government where citizens have the power to elect their leaders in free and fair elections. If citizens are unable to do this, it undermines the democratic process. Federalism, totalitarianism, and oligarchy are different forms of government and are not directly threatened by the inability of citizens to elect their leaders.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>22","subject":"Civic Education","year":"2019","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS","question":"Being faithful in marriage can greatly assist to prevent","images":[],"options":{"A":"unhealthy growth.","B":"extravagancy.","C":"hatred.","D":"HIV infection."},"answer":"D","explanation":"Being faithful in marriage can greatly assist to prevent HIV infection. This is because HIV can be transmitted through sexual intercourse with an infected person. Therefore, being faithful to one's partner reduces the risk of exposure to the virus.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>23","subject":"Civic Education","year":"2019","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY","question":"Which of the following is a punitive measure against cultism?","images":[],"options":{"A":"Counselling and enlightenment in school","B":"A true and sincere religious inculcation","C":"Arrest and prosecution of suspects","D":"Good parental responsibility and care"},"answer":"C","explanation":"A punitive measure is a form of punishment imposed for breaking a law or rule. In the context of cultism, the most direct punitive measure would be the arrest and prosecution of suspects. This is because it directly punishes those involved in cultism and serves as a deterrent for others. Counselling, religious inculcation, and good parental responsibility are preventive measures, not punitive measures.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>24","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS","question":"Use the image in Figure 1 to answer this question      The road sign in Figure 1 indicates","images":["data:image/png;base64,"],"options":{"A":"move ahead","B":"stop ahead","C":"speed limit","D":"wait a bit"},"answer":"A","explanation":"The road sign in figure I indicates move ahead. This is the most appropriate answer.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>25","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS","question":"Authorized road users include the following except","images":[],"options":{"A":"pedestrians.","B":"bicycle riders.","C":"roller skaters.","D":"tricycle riders."},"answer":"C","explanation":"Authorized road users are those who are legally allowed to use the road. This includes pedestrians, bicycle riders, and tricycle riders. Roller skaters are not typically considered authorized road users because they can pose a safety risk to themselves and others on the road. Therefore, the correct answer is 'roller skaters'.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>26","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT","question":"Which of the following is not a function of the judicial arm of government?","images":[],"options":{"A":"Implementation of the law","B":"Pronouncement of punishment","C":"Adjudication of cases","D":"Interpretation of the law"},"answer":"A","explanation":"The judicial arm of government is responsible for the interpretation of the law, adjudication of cases, and pronouncement of punishment. It does not implement the law. That is the function of the executive arm of government. Therefore, the correct answer is 'Implementation of the law'.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>27","subject":"Civic Education","year":"2019","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING","question":"Trafficked children are likely to experience all the following except","images":[],"options":{"A":"empowerment.","B":"prostitution.","C":"forced labour.","D":"unwanted pregnancy."},"answer":"A","explanation":"Child trafficking is a form of child abuse where children are recruited, moved or transported and then exploited, forced to work or sold. The experiences of trafficked children are often of severe abuse, exploitation, and violence. Empowerment, which is the process of becoming stronger and more confident, especially in controlling one's life and claiming one's rights, is not a likely experience for trafficked children. Therefore, the correct answer is 'empowerment'.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>28","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY","question":"Which of the following is not a way of promoting national consciousness?","images":[],"options":{"A":"Inter-school debate","B":"Multicultural education","C":"Sporting festivals","D":"Compensatory mechanism"},"answer":"D","explanation":"National consciousness is a form of collective consciousness that is directed towards the nation. It involves a strong identification with the nation and a shared understanding of the nation's history, present, and future. Ways of promoting national consciousness include inter-school debates, multicultural education, and sporting festivals, which all foster a sense of unity, shared identity, and understanding. However, a compensatory mechanism, which is a psychological strategy whereby a person makes up for a deficiency in one area by excelling or overachieving in another, does not directly contribute to promoting national consciousness. Therefore, the correct answer is 'Compensatory mechanism'.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>29","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT","question":"The totality of legislative, executive and judicial powers constitutes","images":[],"options":{"A":"sovereignty.","B":"authority.","C":"state.","D":"government."},"answer":"A","explanation":"The totality of legislative, executive and judicial powers constitutes sovereignty. Sovereignty refers to the full right and power of a governing body over itself, without any interference from outside sources or bodies. In political theory, sovereignty is a substantive term designating supreme legitimate authority over some polity. It is a basic principle underlying the dominant Westphalian model of state foundation.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>30","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-COMMUNAL RELATIONSHIPS","question":"Use the passage below to answer this question  Ate and Ube are two towns that have lived peacefully in the past years. Last year, they met and decided to build a hospital and raised fund towards the project. Everyone played his/her part to see that the completion of the project becomes a reality. The project was completed within six months.    What existed between Ate and Ube towns can best be termed","images":[],"options":{"A":"boldness.","B":"commitment.","C":"courage.","D":"co-operation."},"answer":"D","explanation":"The relationship between Ate and Ube towns can best be termed as co-operation. This is because they worked together in harmony to achieve a common goal, which was the completion of the hospital project. Co-operation refers to the process of groups of organisms working or acting together for common, mutual, or some underlying benefit, as opposed to working in competition for selfish benefit.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>31","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : IMPORTANCE OF INTER-COMMUNAL RELATIONSHIPS","question":"Use the passage below to answer this question  Ate and Ube are two towns that have lived peacefully in the past years. Last year, they met and decided to build a hospital and raised fund towards the project. Everyone played his/her part to see that the completion of the project becomes a reality. The project was completed within six months.  The relationship that existed between Ate and Ube towns will lead to all the following except","images":[],"options":{"A":"promotion of harmony","B":"unification","C":"stunted development","D":"achievement of goals"},"answer":"C","explanation":"The relationship between Ate and Ube towns is described as peaceful and cooperative, with both towns working together to build a hospital. This kind of relationship would likely promote harmony and unification, and help them achieve their goals. However, there is no reason to believe it would lead to stunted development. In fact, the successful completion of the hospital project suggests the opposite.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>32","subject":"Civic Education","year":"2019","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : REASONS FOR CULTISM","question":"Which of the following categories of students will not likely be a major target of campus cult membership recruitment?","images":[],"options":{"A":"Proud children from wealthy homes","B":"Students with influential parents","C":"Bold and morally upright children","D":"Wayward and fun-loving students."},"answer":"C","explanation":"Campus cults often target individuals who are likely to be influenced or manipulated easily. This includes proud children from wealthy homes, students with influential parents, and wayward and fun-loving students. Bold and morally upright children, on the other hand, are less likely to be targeted for recruitment by campus cults because they are more likely to resist such influences and stand up for what is right.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>33","subject":"Civic Education","year":"2019","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING","question":"What do human traffickers use to instil fear into their victims?","images":[],"options":{"A":"Confrontation","B":"Intimidation","C":"Elimination","D":"Exploitation"},"answer":"B","explanation":"Human traffickers often use intimidation to instil fear into their victims. This can involve threats of violence, manipulation, and other forms of psychological control. Intimidation is a tactic used to control and exploit victims, making them more compliant and less likely to seek help.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>34","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;","question":"The origin of democracy is traced to the","images":[],"options":{"A":"Romans","B":"Greeks","C":"Egyptians","D":"British"},"answer":"B","explanation":"The origin of democracy is traced back to the ancient Greeks in the city-state of Athens around 5th century BC. The term 'democracy' itself is derived from the Greek words 'demos' (people) and 'kratos' (power), meaning 'power to the people'. The Greeks are credited with pioneering the concept of 'rule by the people', which is the fundamental principle of democracy.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>35","subject":"Civic Education","year":"2019","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS","question":"Which of the following skills is needed for youth empowerment?","images":[],"options":{"A":"Cross-curricula skills","B":"Non-cognitive skills","C":"Manipulative skills","D":"Transversal skills"},"answer":"D","explanation":"Transversal skills are needed for youth empowerment. These skills are those that can be applied in various situations and contexts, such as problem-solving, critical thinking, and teamwork. They are essential for youth empowerment as they help young people to adapt to different situations, make informed decisions, and effectively interact with others.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>36","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : FEATURES OF RULE OF LAW","question":"Which of the following is not a feature of federal constitution?","images":[],"options":{"A":"Division of power","B":"Supremacy of the constitution","C":"Flexibility of the constitution","D":"Written constitution"},"answer":"C","explanation":"Flexibility of the constitution is not a feature of a federal constitution. A federal constitution is characterized by a division of power between the central government and the constituent units, supremacy of the constitution, and a written constitution. However, it is not necessarily flexible. In fact, federal constitutions are often rigid to protect the rights and powers of the constituent units.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>37","subject":"Civic Education","year":"2019","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING","question":"Which of the following is not a consequence of human trafficking?","images":[],"options":{"A":"Relative deprivation","B":"Violation of rights","C":"Discontentment of individuals","D":"Family bonding and reunion"},"answer":"D","explanation":"Human trafficking is a serious crime and a grave violation of human rights. It involves the use of force, fraud, or coercion to obtain some type of labor or commercial sex act. The consequences of human trafficking include violation of rights, relative deprivation, and discontentment of individuals. However, family bonding and reunion is not a consequence of human trafficking. In fact, it often results in the opposite - separation of families and loss of familial ties.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>38","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF RULE OF LAW","question":"The principle of rule of law is upheld in the society in order to","images":[],"options":{"A":"protect the citizens from arbitrary rule.","B":"accord immunity to the president.","C":"preserve customs and tradition of the society.","D":"encourage mass literacy and prosperity."},"answer":"A","explanation":"The principle of rule of law is a legal maxim that suggests that no one is above the law and everyone must answer to it. This principle is upheld in society to protect citizens from arbitrary rule, ensuring that laws are fairly applied and enforced. It does not primarily aim to accord immunity to the president, preserve customs and tradition of the society, or encourage mass literacy and prosperity. These may be secondary effects or entirely unrelated to the rule of law.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>39","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;","question":"Constitutional democracy is also known as","images":[],"options":{"A":"communalism","B":"limited government","C":"communism","D":"autocratic government"},"answer":"B","explanation":"Constitutional democracy is also known as limited government. In a constitutional democracy, the power of the government is limited by the constitution, and the rights and freedoms of the citizens are protected.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>40","subject":"Civic Education","year":"2019","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS","question":"Human rights are the cornerstones of","images":[],"options":{"A":"democracy.","B":"plutocracy","C":"aristocracy.","D":"theocracy."},"answer":"A","explanation":"Human rights are the cornerstones of democracy. In a democratic society, the rights and freedoms of all individuals are respected and protected. This includes the right to freedom of speech, the right to freedom of religion, the right to a fair trial, and many others.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>41","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC","question":"In order to guarantee transparency and accountability in governance, leaders should ensure that","images":[],"options":{"A":"constitutionalism thrives.","B":"the judiciary is supervised.","C":"immunity covers government officials.","D":"trials should be held in secret."},"answer":"A","explanation":"Transparency and accountability in governance are best guaranteed when constitutionalism thrives. Constitutionalism is the adherence to a system of constitutional government, which means that all actions and policies of the government are in accordance with the constitution. This ensures that the government is accountable to the people and operates transparently within the confines of the law. The other options do not directly guarantee transparency and accountability in governance.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>42","subject":"Civic Education","year":"2019","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : DIFFERENT CULT GROUPS IN NIGERIA AND THEIR SYMBOLS","question":"Use the diagram in Figure 2 to answer this question    The diagram in Figure 2 symbolizes","images":["data:image/png;base64,"],"options":{"A":"strength","B":"authority","C":"status","D":"power"},"answer":"B","explanation":"The diagram in figure above symbolizes authority. This is the most appropriate answer.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>43","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : WAYS OF DISCOURAGING POLITICAL APATHY","question":"Political apathy can be discouraged through","images":[],"options":{"A":"voter's registration.","B":"registration of more political parties.","C":"support of government policies.","D":"free and fair elections."},"answer":"D","explanation":"Political apathy, which is a lack of interest or concern in politics, can be discouraged through free and fair elections. When elections are free and fair, citizens are more likely to participate in the political process because they believe their votes count and can make a difference. The other options do not directly address the issue of political apathy.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>44","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : THE NEED FOR POPULAR PARTICIPATION IN THE SOCIETY","question":"Use the write-up below to answer this question  Seven months ago, the people of Okiti town were seen in large numbers staging a peaceful protest against the nonchalant attitude of the provincial government concerning the provision of social amenities in the area.  Some government officials came around and listened to their grievances. Today, things have changed for the better in Okiti town. There is a great improvement in infrastructural development and the people of the area now feel the presence of government in their town.    Which of the following is the consequence of government initial attitude towards Okiti community?","images":[],"options":{"A":"Underdevelopment","B":"Corruption","C":"Ignorance","D":"Illiteracy"},"answer":"A","explanation":"The consequence of the government's initial attitude towards the Okiti community was underdevelopment. This is evident from the context of the question where it is stated that the people of Okiti town were protesting against the lack of social amenities in their area. This implies that the area was underdeveloped due to the government's nonchalant attitude. Underdevelopment refers to the state of an area being deprived of infrastructure and basic amenities.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>45","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : THE NEED FOR POPULAR PARTICIPATION IN THE SOCIETY","question":"Use the write-up below to answer this question  Seven months ago, the people of Okiti town were seen in large numbers staging a peaceful protest against the nonchalant attitude of the provincial government concerning the provision of social amenities in the area.  Some government officials came around and listened to their grievances. Today, things have changed for the better in Okiti town. There is a great improvement in infrastructural development and the people of the area now feel the presence of government in their town.  Which of the following is not portrayed in the write-up above?","images":[],"options":{"A":"The importance of decentralization","B":"Government responsiveness","C":"Intra-governmental relations","D":"Freedom of expression"},"answer":"A","explanation":"The importance of decentralization is not portrayed in the write-up. Decentralization refers to the distribution or delegation of functions and powers from a central authority to regional and local authorities. The write-up does not mention anything about the distribution of powers or functions. It only talks about the government's response to the grievances of the people of Okiti town and the subsequent improvement in infrastructural development.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>46","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC","question":"Use the write-up below to answer this question  Seven months ago, the people of Okiti town were seen in large numbers staging a peaceful protest against the nonchalant attitude of the provincial government concerning the provision of social amenities in the area.  Some government officials came around and listened to their grievances. Today, things have changed for the better in Okiti town. There is a great improvement in infrastructural development and the people of the area now feel the presence of government in their town.  From the above write-up, the action of Okiti people received prompt government attention because of the","images":[],"options":{"A":"existence of democratic governance.","B":"need to support minority groups.","C":"need to reward patriotic citizens.","D":"election that was fast approaching."},"answer":"A","explanation":"The action of Okiti people received prompt government attention because of the existence of democratic governance. In a democratic system of governance, the government is accountable to the people and is expected to respond to their needs and grievances. The fact that government officials came around, listened to their grievances, and made improvements indicates that there is a democratic system in place.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2019>47","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;","question":"Democracy could be described as a form of government in which people","images":[],"options":{"A":"develop interest in good governance.","B":"produce sound political manifesto for national development.","C":"participate in the decision making process.","D":"contribute to political liberation."},"answer":"C","explanation":"Democracy is a form of government in which people participate in the decision-making process. This is the fundamental principle of democracy, where the power is vested in the people and they have the right to express their views, opinions, and make decisions that affect their lives. The other options, while they may be aspects of a democratic society, do not define democracy itself.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>48","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY","question":"Which of the following is a focus of the activities of civil society?","images":[],"options":{"A":"Anonymity","B":"Equity","C":"Position seeking","D":"Policy Implementation"},"answer":"B","explanation":"The focus of the activities of civil society is to promote equity. Civil society organizations work to ensure that all individuals and groups in society have equal opportunities and are not discriminated against. They do this by advocating for policies and practices that promote fairness and justice.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>49","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : MEANING OF PUBLIC SERVICE","question":"Which of the following principles prohibits public servants from being seen or heard in the public?","images":[],"options":{"A":"Permanence","B":"Impartiality","C":"Meritocracy","D":"Anonymity"},"answer":"D","explanation":"The principle of anonymity in public service prohibits public servants from being seen or heard in the public. This principle ensures that public servants carry out their duties without seeking personal recognition or publicity. It allows them to remain neutral and impartial, focusing on serving the public interest rather than their own.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2019>50","subject":"Civic Education","year":"2019","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CONSEQUENCES OF POLITICAL APATHY","question":"Which of the following is a consequence of political apathy?","images":[],"options":{"A":"Unrest and secession in the country","B":"Emergence of incompetent leaders","C":"Lack of foreign direct investment","D":"Frequent military intervention"},"answer":"B","explanation":"Political apathy refers to the indifference on the part of any citizen of any country with regard to their attitude towards political activities. It often leads to the emergence of incompetent leaders because when citizens are apathetic, they do not participate in the political process, including voting, and therefore do not contribute to the selection of competent leaders.","marks":"1","difficulty":"2"}];